// Score pilotรฉ par le PROFIL + exclusions (filtre dur) + hashSource canonicalisรฉ.
// Paritรฉ avec workflows/lib/offer-utils.mjs.
const prof=$('Boucle profils').first().json;
const norm=(s)=>String(s??'').toLowerCase().normalize('NFKD').replace(/\s+/g,' ').trim();
const cT=(t)=>norm(t).replace(/\(.*?\)/g,' ').replace(/\b[hf]\s*\/\s*[hfx]\b/g,' ').replace(/\bf\s*\/\s*h\b/g,' ').replace(/[^a-z0-9ร รขรครฉรจรชรซรฎรฏรดรถรนรปรผรง ]/g,' ').replace(/\s+/g,' ').trim();
const cC=(c)=>norm(c).replace(/\b(sas|sasu|sarl|sa|eurl|inc|ltd|llc|gmbh|group|groupe)\b/g,' ').replace(/[^a-z0-9ร รขรครฉรจรชรซรฎรฏรดรถรนรปรผรง ]/g,' ').replace(/\s+/g,' ').trim();
const cL=(l)=>norm(l).replace(/\bfrance\b/g,' ').replace(/[^a-zร รขรครฉรจรชรซรฎรฏรดรถรนรปรผรง ]/g,' ').replace(/\s+/g,' ').trim();
const DEF={keywords:['ia','intelligence artificielle','ml','machine learning','data','llm','python','dรฉveloppeur','developpeur','backend','api'],juniorTerms:['junior','dรฉbutant','debutant','alternance','apprenti','stage','stagiaire','entry level'],seniorTerms:['senior','confirmรฉ','confirme','lead','principal','5 ans','expรฉrimentรฉ','experimente','10 ans'],remoteTerms:['tรฉlรฉtravail','teletravail','remote','hybride','distanciel'],goodContracts:['cdi','alternance','cdd','apprentissage','freelance']};
const sw=(s)=>norm(s).split(/[,;\n\s]+/).filter(Boolean);
const sp=(s)=>String(s??'').split(/[,;\n]+/).map(norm).filter(Boolean);
const kw=[...sw(prof.keywords),...sp(prof.must_have)];
const ct=sp(prof.contract_types);
const P={keywords:kw.length?kw:DEF.keywords,exclusions:sp(prof.exclusions),contractTypes:ct.length?ct:DEF.goodContracts,seniority:norm(prof.seniority)};
function sen(hay){const j=DEF.juniorTerms.some(t=>hay.includes(norm(t)));const se=DEF.seniorTerms.some(t=>hay.includes(norm(t)));const w=P.seniority;if(/junior|alternance|dรฉbutant|debutant|apprenti|stage/.test(w)){if(j&&!se)return 20;return se?0:10;}if(/senior|confirm|lead|expรฉrim|experim/.test(w)){if(se&&!j)return 20;return j?5:10;}return se&&!j?5:12;}
function score(o){const hay=norm(`${o.title} ${o.description} ${o.contract_type}`);const loc=norm(o.location);let s=0;s+=Math.min(40,P.keywords.filter(k=>hay.includes(norm(k))).length*10);s+=sen(hay);if(DEF.remoteTerms.some(t=>hay.includes(norm(t))||loc.includes(norm(t))))s+=15;if(P.contractTypes.some(c=>hay.includes(norm(c))||norm(o.contract_type).includes(norm(c))))s+=15;if(norm(o.salary))s+=10;return Math.max(0,Math.min(100,Math.round(s)));}
function exc(o){if(!P.exclusions.length)return false;const hay=norm(`${o.title} ${o.description} ${o.contract_type} ${o.location}`);return P.exclusions.some(x=>x&&hay.includes(norm(x)));}
return $input.all().map(({json:o})=>o).filter(o=>!exc(o)).map((o)=>({json:{...o,score:score(o),profile_id:prof.id,hashSource:[cT(o.title),cC(o.company),cL(o.location)].join('|')}}));

// Dรฉdup SรMANTIQUE intra-collecte : embeddings (service fastembed) + cosinus.
// Attrape les quasi-doublons inter-sources d'un mรชme lot que le hash exact rate
// (mรชme offre FT + JobSpy reformulรฉe). Paritรฉ avec workflows/lib/offer-utils.mjs.
// Tolรฉrant : service indispo / rรฉponse incohรฉrente -> on n'รฉcarte rien.
const items = $input.all().map(i => i.json);
if (!items.length) return [];
const norm = (s) => String(s ?? '').toLowerCase().normalize('NFKD').replace(/\s+/g, ' ').trim();
const cC = (c) => norm(c).replace(/\b(sas|sasu|sarl|sa|eurl|inc|ltd|llc|gmbh|group|groupe)\b/g, ' ').replace(/[^a-z0-9ร รขรครฉรจรชรซรฎรฏรดรถรนรปรผรง ]/g, ' ').replace(/\s+/g, ' ').trim();
const embText = (o) => [o.title, o.company, o.location, String(o.description || '').replace(/\s+/g, ' ').trim().slice(0, 500)].map(x => String(x ?? '').trim()).filter(Boolean).join(' \n ');
const cos = (a, b) => { let d = 0, na = 0, nb = 0; for (let i = 0; i < a.length; i++) { d += a[i]*b[i]; na += a[i]*a[i]; nb += b[i]*b[i]; } return na && nb ? d/(Math.sqrt(na)*Math.sqrt(nb)) : 0; };
const THRESH = 0.80;
const url = ($env.EMBEDDINGS_API_URL || 'http://embeddings:8002') + '/embed';
let vecs;
try {
  const resp = await this.helpers.httpRequest({ method: 'POST', url, body: { texts: items.map(embText) }, json: true });
  vecs = resp.embeddings;
} catch (e) {
  return items.map(json => ({ json }));
}
if (!Array.isArray(vecs) || vecs.length !== items.length) return items.map(json => ({ json }));
const kept = [], keptVecs = [];
let dropped = 0;
for (let i = 0; i < items.length; i++) {
  const v = vecs[i];
  let dup = false;
  for (let k = 0; k < kept.length; k++) {
    const a = cC(items[i].company), b = cC(kept[k].company);
    const sameCompany = a && b ? a === b : true;
    if (sameCompany && cos(v, keptVecs[k]) >= THRESH) { dup = true; break; }
  }
  if (dup) { dropped++; continue; }
  kept.push(items[i]); keptVecs.push(v);
}
console.log(`Dedup semantique : ${dropped} quasi-doublon(s) ecarte(s) sur ${items.length}.`);
return kept.map(json => ({ json }));

// Affinage LLM du top-N avec must_have/exclusions DU PROFIL (cf. llm-scoring.mjs).
const prof=$('Boucle profils').first().json;
const all=$input.all().map(i=>i.json);
const offers=[...all].sort((a,b)=>(b.score??0)-(a.score??0)).slice(0,20);
const system="Tu es un expert en recrutement. Barรจme: 90-100 = correspond trรจs bien aux critรจres indispensables et aucune exclusion; 50-89 = partiel; <50 = hors sujet ou exclusion. Rรฉponds UNIQUEMENT en JSON {\"scores\":[{\"i\":<index>,\"score\":<0-100>,\"reason\":\"<une phrase>\"}]}.";
const list=offers.map((o,i)=>`#${i} โ ${o.title||'?'} @ ${o.company||'?'} (${o.location||'?'})\n${String(o.description||'').slice(0,600)}`).join('\n\n');
const user=`Critรจres indispensables : ${prof.must_have||'(non prรฉcisรฉs)'}\nCritรจres d'exclusion : ${prof.exclusions||'(aucun)'}\n\nOFFRES:\n${list}`;
return [{json:{messages:[{role:'system',content:system},{role:'user',content:user}],offers,threshold:prof.score_threshold||60}}];

const clamp=(n)=>Math.max(0,Math.min(100,Math.round(Number(n)||0)));
const raw=$input.first().json.choices?.[0]?.message?.content??'';
const offers=$('Prรฉparer scoring LLM').first().json.offers||[];
let data;try{data=JSON.parse(raw);}catch{data=null;}
const byI=new Map();for(const s of (data?.scores??[]))if(Number.isInteger(s.i))byI.set(s.i,s);
return offers.map((o,i)=>{const s=byI.get(i);return{json:(!s||s.score==null)?o:{...o,score:clamp(s.score),score_reason:String(s.reason??'')}};});

